target.expr:
sum by (pod, reason) (
  max_over_time(
    kube_pod_status_reason{
      namespace=~"$namespace",
      pod=~"$workload.*",
      reason=~"Evicted|NodeLost"
    }[$__interval]
  ) > 0
) or increase(
  kube_pod_container_status_restarts_total{pod=~"$workload.*"}[$__rate_interval]
)
* on(pod, container) group_left(reason)
kube_pod_container_status_last_terminated_reason{pod=~"$workload.*", reason!="Completed"} > 0

